  { tokens: [{ t: "", c: "plain" }] },
  { tokens: [{ t: "const", c: "keyword" }, { t: " build", c: "fn" }, { t: " = ", c: "plain" }, { t: "pipeline", c: "fn" }, { t: "()", c: "plain" }] },
  { tokens: [{ t: "  .", c: "plain" }, { t: "source", c: "method" }, { t: '("./src")', c: "plain" }] },
  { tokens: [{ t: "  .", c: "plain" }, { t: "transform", c: "method" }, { t: "(ts, minify)", c: "plain" }] },
  { tokens: [{ t: "  .", c: "plain" }, { t: "bundle", c: "method" }, { t: '({ target: "esnext" })', c: "plain" }] },
  { tokens: [{ t: "  .", c: "plain" }, { t: "emit", c: "method" }, { t: '("./dist")', c: "plain" }] },
  { tokens: [{ t: "", c: "plain" }] },
  { tokens: [{ t: "await", c: "keyword" }, { t: " build.", c: "plain" }, { t: "run", c: "fn" }, { t: "()", c: "plain" }, { t: "  // 38ms ✓", c: "comment" }] },
];

const colorMap: Record<string, string> = {
  keyword: "#f59e0b",
  fn: "#fbbf24",
  method: "#d97706",
  string: "#86efac",
  comment: "#4b5563",
  plain: "#e5e7eb",
};

function useTypingLines(lines: typeof CODE_LINES, speed = 18) {
  const [revealed, setRevealed] = useState(0);
  useEffect(() => {
    if (revealed >= lines.length) return;
    const t = setTimeout(() => setRevealed((r) => r + 1), speed * 12);
    return () => clearTimeout(t);
  }, [revealed, lines.length, speed]);
  return revealed;
}

